inline int maximum(int a, int b, int c)
{
    int k;
    if (a <= b)
        k = b;
    else
        k = a;

    if (k <= c)
        return c;
    else
        return k;
}

#define TEMP(y, x) temp[(y) * (BLOCK_SIZE + 1) + (x)]
#define REF(y, x)  ref[(y) * BLOCK_SIZE + (x)]

__kernel void nw_kernel1(__global int *referrence,
                         __global int *input_itemsets,
                         __global int *output_itemsets,
                         __local int *temp,
                         __local int *ref,
                         int cols,
                         int penalty,
                         int blk,
                         int block_width,
                         int worksize,
                         int offset_r,
                         int offset_c)
{
    int bx = (int)get_group_id(0);
    int tx = (int)get_local_id(0);

    int b_index_x = bx;
    int b_index_y = blk - 1 - bx;

    int index    = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + (cols + 1);
    int index_n  = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + 1;
    int index_w  = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + cols;
    int index_nw = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;

    if (tx == 0)
        TEMP(0, 0) = input_itemsets[index_nw];

    for (int ty = 0; ty < BLOCK_SIZE; ty++)
        REF(ty, tx) = referrence[index + cols * ty];

    barrier(CLK_LOCAL_MEM_FENCE);

    TEMP(tx + 1, 0) = input_itemsets[index_w + cols * tx];

    barrier(CLK_LOCAL_MEM_FENCE);

    TEMP(0, tx + 1) = input_itemsets[index_n];

    barrier(CLK_LOCAL_MEM_FENCE);

    for (int m = 0; m < BLOCK_SIZE; m++) {
        if (tx <= m) {
            int t_index_x = tx + 1;
            int t_index_y = m - tx + 1;

            TEMP(t_index_y, t_index_x) =
                maximum(TEMP(t_index_y - 1, t_index_x - 1) + REF(t_index_y - 1, t_index_x - 1),
                        TEMP(t_index_y,     t_index_x - 1) - penalty,
                        TEMP(t_index_y - 1, t_index_x    ) - penalty);
        }
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    for (int m = BLOCK_SIZE - 2; m >= 0; m--) {
        if (tx <= m) {
            int t_index_x = tx + BLOCK_SIZE - m;
            int t_index_y = BLOCK_SIZE - tx;

            TEMP(t_index_y, t_index_x) =
                maximum(TEMP(t_index_y - 1, t_index_x - 1) + REF(t_index_y - 1, t_index_x - 1),
                        TEMP(t_index_y,     t_index_x - 1) - penalty,
                        TEMP(t_index_y - 1, t_index_x    ) - penalty);
        }
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    for (int ty = 0; ty < BLOCK_SIZE; ty++) {
        int out_idx = index + ty * cols;
        int val = TEMP(ty + 1, tx + 1);
        input_itemsets[out_idx] = val;
        output_itemsets[out_idx] = val;
    }

    (void)block_width;
    (void)worksize;
    (void)offset_r;
    (void)offset_c;
}

